{"title":"jjj","content":"/* Skrypt logiki obsługujący natywny Panel Boczny Edge */

const CONFIG = {
    // Zmieniono 'urgent' z 15 na 10 zgodnie z prośbą (10 min przed końcem +30)
    timeThresholds: { urgent: 10, warning: 30, upcoming: 60 },
    colors: {
        urgentAlert: '#FF0000', progress: '#CE9105', finished: '#03C314', outCol: '#555555'
    }
};

const sspStatusState = { hasData: false, dataCount: 0, paused: false };

function updateSSPHeaderStatus() {
    const el = document.getElementById('ssp-header-status');
    if (!el) return;
    const refreshLabel = sspStatusState.paused ? 'Pauza' : 'Odświeżanie';
    const dataLabel = sspStatusState.hasData ? 'Dane: ' + sspStatusState.dataCount : 'Dane: —';
    el.textContent = refreshLabel + ' · ' + dataLabel;
    el.classList.toggle('ssp-status-paused', sspStatusState.paused);
    el.classList.toggle('ssp-status-hasdata', sspStatusState.hasData);
}

function calculateMinutes(baseTime) {
    const [h, m] = baseTime.split(':').map(Number);
    const target = new Date();
    // Dodaje 30 minut do czasu z wiersza
    target.setHours(h, m + 30, 0, 0);
    return Math.round((target - new Date()) / 60000);
}

// Odbieranie danych z content.js
chrome.runtime.onMessage.addListener((message) => {
    if (message.type === "SSP_UPDATE_DATA") {
        sspStatusState.hasData = true;
        sspStatusState.dataCount = (message.payload && message.payload.length) || 0;
        updateSSPHeaderStatus();
        renderSidebar(message.payload);
    }
});

function renderSidebar(dataArray) {
    const counts = { scheduled: 0, progress: 0, finished: 0 };
    let dataCounts = { critical: 0, progress: 0, finished: 0, out: 0 };
    let htmlData = { critical: "", progress: "", finished: "", out: "" };

    dataArray.forEach(item => {
        const diff = calculateMinutes(item.baseTime);

        // Zliczanie podstawowych statystyk
        if (item.status.includes("Scheduled")) counts.scheduled++;
        else if (item.status.includes("Progress")) counts.progress++;
        else if (item.status.includes("Finished")) counts.finished++;

        const cardBody = `
            <div class="card-body">
                <div class="trailer-huge"><span>TRAILER:</span>${item.trailer}</div>
                <div class="data-row"><span>STATUS:</span> <b>${item.status.toUpperCase()}</b></div>
                <div class="data-row"><span>REF:</span> <b>${item.ref}</b></div>
                <div class="data-row"><span>CARR:</span> <b title="${item.carrier}">${item.carrier}</b></div>
                <div class="data-row"><span>LOC:</span> <b>${item.loc}</b></div>
            </div>`;

        if (diff > -120 && diff < 180) {
            if (item.status.includes("Finished") || item.status.toUpperCase() === "OUT") {
                if (diff <= 0 || item.status.toUpperCase() === "OUT") {
                    dataCounts.out++;
                    htmlData.out += `
                        <div class="ssp-card" style="border-left-color: ${CONFIG.colors.outCol}; opacity: 0.8;">
                            <div class="card-header"><span style="color:var(--text-muted)">[OUT] ${item.baseTime}</span><span class="time-badge" style="color:var(--text-muted)">T: ${diff}m</span></div>
                            <div class="card-body">
                                <div class="trailer-huge" style="text-decoration: line-through;"><span>TRAILER:</span>${item.trailer}</div>
                                <div class="data-row"><span>STATUS:</span> <b>DEPARTED</b></div>
                                <div class="data-row"><span>REF:</span> <b>${item.ref}</b></div>
                                <div class="data-row"><span>LOC:</span> <b>${item.loc}</b></div>
                            </div>
                        </div>`;
                } else {
                    dataCounts.finished++;
                    htmlData.finished += `
                        <div class="ssp-card" style="border-left-color: ${CONFIG.colors.finished}">
                            <div class="card-header" style="color: ${CONFIG.colors.finished}"><span>${item.baseTime} (+30)</span><span class="time-badge" style="color:${CONFIG.colors.finished}">WAIT: ${diff}m</span></div>
                            ${cardBody}
                        </div>`;
                }
            } else if (!item.status.includes("Scheduled")) {
                const isUrgent = diff <= CONFIG.timeThresholds.urgent;
                const cColor = isUrgent ? CONFIG.colors.urgentAlert : CONFIG.colors.progress;
                const activeCard = `
                    <div class="ssp-card" style="border-left-color: ${cColor}">
                        <div class="card-header" style="color: ${cColor}">
                            <span>${item.baseTime} (+30)</span>
                            <span class="time-badge ${isUrgent ? 'urgent-blink' : ''}" style="background:${isUrgent ? cColor : 'transparent'}; color:${isUrgent ? '#fff' : 'var(--text-muted)'};">IN: ${diff}m</span>
                        </div>
                        ${cardBody}
                    </div>`;

                if (isUrgent) { dataCounts.critical++; htmlData.critical += activeCard; }
                else { dataCounts.progress++; htmlData.progress += activeCard; }
            }
        }
    });

    // Aktualizacja STATS
    document.getElementById('st-sch').innerText = counts.scheduled;
    document.getElementById('st-pro').innerText = counts.progress;
    document.getElementById('st-fin').innerText = counts.finished;

    // Aktualizacja TABS
    document.getElementById('tab-cnt-critical').innerText = `(${dataCounts.critical})`;
    document.getElementById('tab-cnt-progress').innerText = `(${dataCounts.progress})`;
    document.getElementById('tab-cnt-finished').innerText = `(${dataCounts.finished})`;
    document.getElementById('tab-cnt-out').innerText = `(${dataCounts.out})`;

    // Aktualizacja HTML
    const emptyMsg = `<div style="text-align:center; padding:20px; color:var(--text-muted); font-weight:bold; font-size: 11px;">[ BRAK DANYCH ]</div>`;
    document.getElementById('pane-critical').innerHTML = htmlData.critical || emptyMsg;
    document.getElementById('pane-progress').innerHTML = htmlData.progress || emptyMsg;
    document.getElementById('pane-finished').innerHTML = htmlData.finished || emptyMsg;
    document.getElementById('pane-out').innerHTML = htmlData.out || emptyMsg;
}

// --- LOGIKA UI PANELU BOCZNEGO ---
document.addEventListener('DOMContentLoaded', () => {
    // Obsługa zakładek (Tabs)
    const tabBtns = document.querySelectorAll('.ssp-tab-btn');
    const tabPanes = document.querySelectorAll('.ssp-tab-content');

    tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            tabBtns.forEach(b => b.classList.remove('active'));
            tabPanes.forEach(p => p.classList.remove('active'));

            btn.classList.add('active');
            document.getElementById(`pane-${btn.dataset.tab}`).classList.add('active');
        });
    });

    // Motyw (Dark/Light) – zapamiętywany w storage (chrome.storage lub browser.storage)
    const THEME_KEY = 'sspTheme';
    let isDark = false;
    const storage = (typeof chrome !== 'undefined' && chrome.storage && chrome.storage.local)
        ? chrome.storage.local
        : (typeof browser !== 'undefined' && browser.storage && browser.storage.local)
            ? browser.storage.local
            : null;

    function applyTheme(dark) {
        isDark = !!dark;
        document.documentElement.setAttribute('data-theme', isDark ? 'dark' : 'light');
    }

    if (storage) {
        try {
            storage.get(THEME_KEY, function (result) {
                try {
                    const saved = (result && result[THEME_KEY]) || null;
                    if (saved === 'dark' || saved === 'light') {
                        applyTheme(saved === 'dark');
                    }
                } catch (_) { }
            });
        } catch (_) { }
    }

    document.getElementById('toggle-theme').onclick = () => {
        applyTheme(!isDark);
        if (storage) {
            storage.set({ [THEME_KEY]: isDark ? 'dark' : 'light' }).catch(function () { });
        }
    };

    // Cancel = odśwież teraz, Pause = wstrzymaj/wznów odświeżanie
    const btnCancel = document.getElementById('btn-cancel');
    const btnPause = document.getElementById('btn-pause');
    let pollingPaused = false;

    function sendToTab(type, callback) {
        chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
            const tabId = tabs[0]?.id;
            if (!tabId) return callback?.();
            chrome.tabs.sendMessage(tabId, { type }, (err) => {
                if (chrome.runtime.lastError) { /* strona bez content script */ }
                callback?.();
            });
        });
    }

    btnCancel.onclick = () => sendToTab('SSP_REFRESH_NOW');
    btnPause.onclick = () => {
        pollingPaused = !pollingPaused;
        sspStatusState.paused = pollingPaused;
        updateSSPHeaderStatus();
        sendToTab(pollingPaused ? 'SSP_PAUSE_POLLING' : 'SSP_RESUME_POLLING', () => {
            const iconPause = btnPause.querySelector('.btn-icon-pause');
            const iconPlay = btnPause.querySelector('.btn-icon-play');
            if (iconPause) iconPause.hidden = pollingPaused;
            if (iconPlay) iconPlay.hidden = !pollingPaused;
            btnPause.title = pollingPaused ? 'Wznów odświeżanie' : 'Wstrzymaj odświeżanie';
            btnPause.setAttribute('aria-label', pollingPaused ? 'Wznów' : 'Pauza');
        });
    };

    updateSSPHeaderStatus();
});"}

{"title":"yuyu","content":"/* Skrypt zbierający dane ze strony (Niewidoczny dla użytkownika) */

function calculateMinutes(baseTime) {
    const [h, m] = baseTime.split(':').map(Number);
    const target = new Date();
    target.setHours(h, m + 30, 0, 0);
    return Math.round((target - new Date()) / 60000);
}

function extractData() {
    const rows = document.querySelectorAll("table.dataTable tbody tr");
    const extractedData = [];

    rows.forEach(row => {
        const text = row.innerText;
        const status = row.cells[3]?.innerText.trim() || "";
        const timeMatch = text.match(/\d{2}:\d{2}/);

        if (timeMatch && status !== "") {
            const baseTime = timeMatch[0];
            const loc = row.cells[5]?.innerText.trim() || '---';
            const ref = row.cells[6]?.innerText.trim() || '---';
            const carrier = row.cells[8]?.innerText.trim() || '---';
            const trailer = row.cells[9]?.innerText.trim() || '---';

            extractedData.push({
                baseTime: baseTime,
                status: status,
                loc: loc,
                ref: ref,
                carrier: carrier,
                trailer: trailer
            });

            // --- KOLOROWANIE WIERSZY NA STRONIE ---
            const diff = calculateMinutes(baseTime);
            let bgColor = "";

            if (diff > -120 && diff < 180) {
                if (status.includes("Finished") || status.toUpperCase() === "OUT") {
                    if (diff <= 0 || status.toUpperCase() === "OUT") {
                        bgColor = "rgba(85, 85, 85, 0.25)"; // OUT (Szary)
                    } else {
                        bgColor = "rgba(3, 195, 20, 0.25)"; // FINISHED (Zielony)
                    }
                } else if (!status.includes("Scheduled")) {
                    if (diff <= 10) {
                        bgColor = "rgba(255, 0, 0, 0.3)"; // CRITICAL (Czerwony - alert 10 min)
                    } else {
                        bgColor = "rgba(206, 145, 5, 0.25)"; // PROGRESS (Pomarańczowy)
                    }
                }
            }

            // Aplikowanie koloru na wiersz i wszystkie jego komórki z użyciem !important
            if (bgColor) {
                row.style.setProperty('background-color', bgColor, 'important');
                Array.from(row.cells).forEach(cell => {
                    cell.style.setProperty('background-color', bgColor, 'important');
                });
            } else {
                row.style.removeProperty('background-color');
                Array.from(row.cells).forEach(cell => {
                    cell.style.removeProperty('background-color');
                });
            }
        }
    });

    // Wysłanie danych do panelu bocznego
    if (typeof chrome !== 'undefined' && chrome.runtime) {
        chrome.runtime.sendMessage({
            type: "SSP_UPDATE_DATA",
            payload: extractedData
        }).catch(() => {
            // Ignoruj błąd, jeśli panel boczny jest zamknięty
        });
    }
}

let refreshIntervalId = null;
let refreshIntervalMs = 15000;
let pollingPaused = false;

function startRefreshInterval() {
    if (refreshIntervalId !== null) clearInterval(refreshIntervalId);
    refreshIntervalId = setInterval(extractData, refreshIntervalMs);
}

function updateBarIntervalText() {
    const el = document.getElementById('ssp-interval-text');
    if (!el) return;
    if (pollingPaused) {
        el.textContent = 'Pauza';
        el.classList.add('paused');
    } else {
        el.textContent = `Odświeżanie co ${refreshIntervalMs / 1000} s`;
        el.classList.remove('paused');
    }
}

// Wiadomości z panelu bocznego: pauza / wznów / odśwież teraz
if (typeof chrome !== 'undefined' && chrome.runtime && chrome.runtime.onMessage) {
    chrome.runtime.onMessage.addListener((message, _sender, sendResponse) => {
        if (message.type === "SSP_PAUSE_POLLING") {
            if (refreshIntervalId !== null) {
                clearInterval(refreshIntervalId);
                refreshIntervalId = null;
            }
            pollingPaused = true;
            updateBarIntervalText();
            sendResponse({ ok: true, paused: true });
        } else if (message.type === "SSP_RESUME_POLLING") {
            pollingPaused = false;
            if (refreshIntervalId === null) startRefreshInterval();
            updateBarIntervalText();
            sendResponse({ ok: true, paused: false });
        } else if (message.type === "SSP_REFRESH_NOW") {
            extractData();
            sendResponse({ ok: true });
        }
        return true;
    });
}

// Inicjalizacja obserwatora na stronie Amazona
if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", initObserver);
} else {
    initObserver();
}

function injectTopBarAndModal() {
    if (document.getElementById('ssp-top-bar')) return;

    const bar = document.createElement('div');
    bar.id = 'ssp-top-bar';
    bar.innerHTML = `
        <div class="ssp-bar-left">
            <span class="ssp-bar-title">
                <svg class="ssp-bar-logo" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="border-radius: 0;"><rect x="2" y="4" width="20" height="14" rx="2"/><path d="M2 10h20M6 10v4M10 10v4M14 10v4M18 10v4"/></svg>
                SSP Terminal [Edge]
            </span>
            <span id="ssp-interval-text" class="ssp-bar-interval">Odświeżanie co 15 s</span>
        </div>
        <div class="ssp-bar-actions">
            <button type="button" id="ssp-btn-settings" style="border-radius: 0;">
                <svg class="ssp-btn-icon" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="3"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>
                Ustawienia
            </button>
        </div>
    `;

    const overlay = document.createElement('div');
    overlay.id = 'ssp-modal-overlay';
    overlay.innerHTML = `
        <div id="ssp-modal-box" style="border-radius: 0;">
            <div class="ssp-modal-header">
                <svg class="ssp-modal-header-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="3"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>
                Ustawienia
            </div>
            <div class="ssp-modal-body">
                <label for="ssp-interval-input">Odśwież co (sekund):</label>
                <input type="number" id="ssp-interval-input" min="5" max="300" value="15" step="1" style="border-radius: 0;">
            </div>
            <div class="ssp-modal-footer">
                <button type="button" id="ssp-modal-cancel" style="border-radius: 0;"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg> Anuluj</button>
                <button type="button" id="ssp-modal-save" class="primary" style="border-radius: 0;"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M20 6L9 17l-5-5"/></svg> Zapisz</button>
            </div>
        </div>
    `;

    document.body.prepend(overlay);
    document.body.prepend(bar);
    document.body.classList.add('ssp-bar-visible');

    const openModal = () => {
        document.getElementById('ssp-interval-input').value = refreshIntervalMs / 1000;
        overlay.classList.add('open');
        overlay.style.display = 'flex';
    };
    const closeModal = () => {
        overlay.classList.remove('open');
        overlay.style.display = 'none';
    };

    document.getElementById('ssp-btn-settings').addEventListener('click', openModal);
    document.getElementById('ssp-modal-cancel').addEventListener('click', closeModal);
    overlay.addEventListener('click', (e) => { if (e.target === overlay) closeModal(); });
    document.getElementById('ssp-modal-box').addEventListener('click', (e) => e.stopPropagation());

    document.getElementById('ssp-modal-save').addEventListener('click', () => {
        const val = parseInt(document.getElementById('ssp-interval-input').value, 10);
        if (val >= 5 && val <= 300) {
            refreshIntervalMs = val * 1000;
            if (!pollingPaused) {
                startRefreshInterval();
            }
            updateBarIntervalText();
            closeModal();
        }
    });
}

function initObserver() {
    injectTopBarAndModal();
    updateBarIntervalText();

    const obs = new MutationObserver(extractData);
    const table = document.querySelector('table.dataTable');
    if (table) {
        obs.observe(table, { childList: true, subtree: true });
    }
    extractData();
    startRefreshInterval();
}"}

